--
-- Table structure for table `dataset_versions`
--

DROP TABLE IF EXISTS `dataset_versions`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `dataset_versions` (
  `id` int(11) unsigned NOT NULL AUTO_INCREMENT,
  `dataset_id` int(11) unsigned NOT NULL,
  `version` varchar(20) NOT NULL,
  `change_summary` text DEFAULT NULL,
  `dataset_file_id` int(11) unsigned DEFAULT NULL,
  `created_by` int(11) unsigned NOT NULL,
  `created_at` datetime DEFAULT NULL,
  `updated_at` datetime DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `dataset_versions_dataset_id_foreign` (`dataset_id`),
  KEY `dataset_versions_dataset_file_id_foreign` (`dataset_file_id`),
  KEY `dataset_versions_created_by_foreign` (`created_by`),
  CONSTRAINT `dataset_versions_created_by_foreign` FOREIGN KEY (`created_by`) REFERENCES `users` (`id`) ON DELETE CASCADE ON UPDATE CASCADE,
  CONSTRAINT `dataset_versions_dataset_file_id_foreign` FOREIGN KEY (`dataset_file_id`) REFERENCES `dataset_files` (`id`) ON DELETE SET NULL ON UPDATE SET NULL,
  CONSTRAINT `dataset_versions_dataset_id_foreign` FOREIGN KEY (`dataset_id`) REFERENCES `datasets` (`id`) ON DELETE CASCADE ON UPDATE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=125 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

