DROP TABLE IF EXISTS `datasets`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `datasets` (
  `id` int(11) unsigned NOT NULL AUTO_INCREMENT,
  `title` varchar(255) NOT NULL,
  `description` text NOT NULL,
  `category` varchar(120) NOT NULL,
  `tags` varchar(255) DEFAULT NULL,
  `data_type` varchar(80) NOT NULL,
  `file_format` varchar(30) NOT NULL,
  `source_type` varchar(80) NOT NULL,
  `source_link` varchar(255) DEFAULT NULL,
  `form` varchar(80) DEFAULT NULL,
  `research_title` varchar(255) NOT NULL,
  `project_head` varchar(150) NOT NULL,
  `members` text DEFAULT NULL,
  `contributor_id` int(11) unsigned NOT NULL,
  `status` varchar(30) NOT NULL DEFAULT 'pending',
  `access_type` varchar(30) NOT NULL DEFAULT 'public',
  `version` varchar(20) NOT NULL DEFAULT '1.0',
  `approved_by` int(11) unsigned DEFAULT NULL,
  `approved_at` datetime DEFAULT NULL,
  `archived_at` datetime DEFAULT NULL,
  `archived_from_status` varchar(40) DEFAULT NULL,
  `created_at` datetime DEFAULT NULL,
  `updated_at` datetime DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `datasets_contributor_id_foreign` (`contributor_id`),
  KEY `datasets_approved_by_foreign` (`approved_by`),
  KEY `status_data_type` (`status`,`data_type`),
  CONSTRAINT `datasets_approved_by_foreign` FOREIGN KEY (`approved_by`) REFERENCES `users` (`id`) ON DELETE SET NULL ON UPDATE SET NULL,
  CONSTRAINT `datasets_contributor_id_foreign` FOREIGN KEY (`contributor_id`) REFERENCES `users` (`id`) ON DELETE CASCADE ON UPDATE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=124 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;
